 }
+
+static int
+shm_chmod(struct file *fp, mode_t mode, struct thread *td)
+{
+	struct shmfd *shmfd;
+
+	shmfd = fp->f_data;
+	shmfd->shm_mode = mode & ACCESSPERMS;
+	return (0);
+}
